import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { INITIAL_ITEMS, THEMES } from './constants';
import { ChecklistItem, Theme, View } from './types';
import Dashboard from './components/Dashboard';
import ThemeSelector from './components/ThemeSelector';
import AddItemModal from './components/AddItemModal';

const App: React.FC = () => {
  const [items, setItems] = useState<ChecklistItem[]>(() => {
    const saved = localStorage.getItem('checkly-items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [activeTheme, setActiveTheme] = useState<Theme>(THEMES[3]); // Default Sky Blue
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('checkly-items', JSON.stringify(items));
  }, [items]);

  const toggleItem = useCallback((id: string) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, checked: !item.checked } : item
    ));
  }, []);

  const resetItems = useCallback(() => {
    setItems(prev => prev.map(item => ({ ...item, checked: false })));
  }, []);

  const addItem = useCallback((item: Omit<ChecklistItem, 'id' | 'checked'>) => {
    const newItem: ChecklistItem = {
      ...item,
      id: Math.random().toString(36).substring(2, 9),
      checked: false
    };
    setItems(prev => [newItem, ...prev]);
    setIsAddModalOpen(false);
  }, []);

  const deleteItem = useCallback((id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  }, []);

  return (
    <div className="min-h-screen bg-ios-bg font-sans selection:bg-primary/20">
      <div className="relative flex h-screen w-full flex-col bg-gradient-mesh overflow-hidden max-w-md mx-auto shadow-2xl border-x border-black/[0.05]">

        {/* Counter background number */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0">
          <motion.span 
            key={items.filter(i => !i.checked).length}
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 0.04, scale: 1 }}
            className="text-[280px] font-extrabold select-none tracking-tighter"
          >
            {String(items.filter(i => !i.checked).length).padStart(2, '0')}
          </motion.span>
        </div>

        <AnimatePresence mode="wait">
          {currentView === 'dashboard' && (
            <motion.div
              key="dashboard"
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className="h-full w-full"
            >
              <Dashboard 
                items={items}
                onToggle={toggleItem}
                onReset={resetItems}
                onOpenThemes={() => setCurrentView('themes')}
                onOpenAdd={() => setIsAddModalOpen(true)}
              />
            </motion.div>
          )}

          {currentView === 'themes' && (
            <motion.div
              key="themes"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 20 }}
              className="h-full w-full"
            >
              <ThemeSelector 
                activeTheme={activeTheme}
                onSelectTheme={(theme) => {
                  setActiveTheme(theme);
                  setCurrentView('dashboard');
                }}
                onBack={() => setCurrentView('dashboard')}
              />
            </motion.div>
          )}
        </AnimatePresence>

        <AnimatePresence>
          {isAddModalOpen && (
            <AddItemModal 
              onClose={() => setIsAddModalOpen(false)}
              onAdd={addItem}
            />
          )}
        </AnimatePresence>

        {/* iOS Indicator */}
        <div className="absolute bottom-1.5 left-1/2 -translate-x-1/2 w-32 h-1.5 bg-black/5 rounded-full pointer-events-none"></div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { motion } from 'framer-motion';
import { ChecklistItem } from '../types';

interface DashboardProps {
  items: ChecklistItem[];
  onToggle: (id: string) => void;
  onReset: () => void;
  onOpenThemes: () => void;
  onOpenAdd: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ items, onToggle, onReset, onOpenThemes, onOpenAdd }) => {
  const remainingCount = items.filter(i => !i.checked).length;

  return (
    <div className="relative flex h-full flex-col z-10">
      <header className="flex items-center px-8 pt-16 pb-6 justify-between">
        <div className="flex flex-col">
          <motion.h2 
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-3xl font-extrabold tracking-tight text-black/90"
          >
            Checklist
          </motion.h2>
          <motion.p 
            key={remainingCount}
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-sm font-semibold text-black/40 uppercase tracking-widest"
          >
            {remainingCount} {remainingCount === 1 ? 'item' : 'items'} remaining
          </motion.p>
        </div>
        <button 
          onClick={onOpenThemes}
          className="flex size-12 items-center justify-center rounded-2xl glass-card transition-transform active:scale-90"
        >
          <span className="material-symbols-outlined text-black/70">tune</span>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto px-6 pt-2 pb-40 scroll-smooth no-scrollbar">
        <div className="space-y-4">
          {items.map((item, index) => (
            <motion.div
              layout
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.05 }}
              key={item.id}
              onClick={() => onToggle(item.id)}
              className={`relative group cursor-pointer transition-all duration-300 ${item.checked ? 'opacity-50 grayscale-[0.3]' : ''}`}
            >
              <div className="glass-card flex items-center p-5 rounded-[2rem] active:scale-[0.98] transition-transform">
                <div className={`flex size-14 items-center justify-center rounded-full ${item.color} mr-4 shadow-sm`}>
                  <span className="material-symbols-outlined text-2xl" style={{ fontVariationSettings: "'wght' 500" }}>
                    {item.icon}
                  </span>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className={`text-lg font-bold text-black/80 truncate ${item.checked ? 'line-through' : ''}`}>
                    {item.label}
                  </h3>
                  <p className="text-xs font-semibold text-black/30 truncate">
                    {item.subtext}
                  </p>
                </div>
                <div className={`size-8 rounded-full flex items-center justify-center transition-all duration-300 ${item.checked ? 'bg-primary text-white scale-110' : 'border-2 border-black/10'}`}>
                  {item.checked && (
                    <motion.span 
                      initial={{ scale: 0.5, opacity: 0 }}
                      animate={{ scale: 1, opacity: 1 }}
                      className="material-symbols-outlined text-lg" 
                      style={{ fontVariationSettings: "'wght' 700" }}
                    >
                      check
                    </motion.span>
                  )}
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </main>

      <div className="absolute bottom-12 left-0 right-0 px-8 flex items-center justify-between">
        <motion.button 
          whileTap={{ scale: 0.95 }}
          onClick={onReset}
          className="glass-card px-10 py-5 rounded-3xl text-black/70 font-bold text-xs tracking-[0.2em] uppercase"
        >
          RESET
        </motion.button>
        <motion.button 
          whileTap={{ scale: 0.9 }}
          onClick={onOpenAdd}
          className="size-20 bg-white/40 backdrop-blur-xl border border-white/50 flex items-center justify-center rounded-[2.5rem] shadow-xl shadow-black/5"
        >
          <div className="size-14 bg-black flex items-center justify-center rounded-[1.8rem]">
            <span className="material-symbols-outlined text-white text-3xl" style={{ fontVariationSettings: "'wght' 400" }}>
              add
            </span>
          </div>
        </motion.button>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { motion } from 'framer-motion';
import { Theme } from '../types';
import { THEMES } from '../constants';

interface ThemeSelectorProps {
  activeTheme: Theme;
  onSelectTheme: (theme: Theme) => void;
  onBack: () => void;
}

const ThemeSelector: React.FC<ThemeSelectorProps> = ({ activeTheme, onSelectTheme, onBack }) => {
  return (
    <div className="flex h-full flex-col z-10 px-6 pt-12 pb-10">
      <header className="flex items-center justify-between mb-8">
        <button 
          onClick={onBack}
          className="w-12 h-12 flex items-center justify-center rounded-2xl glass-card transition-transform active:scale-90"
        >
          <span className="material-symbols-outlined">arrow_back_ios_new</span>
        </button>
        <h1 className="text-xl font-extrabold tracking-tight">Personalize</h1>
        <div className="w-12"></div> {/* Spacer */}
      </header>

      <div className="mb-8">
        <h2 className="text-3xl font-bold mb-2">Themes</h2>
        <p className="text-gray-600 font-medium">Choose a vibe for your tracker</p>
      </div>

      <div className="grid grid-cols-2 gap-4 flex-1 overflow-y-auto no-scrollbar">
        {THEMES.map((theme) => (
          <motion.div
            key={theme.id}
            whileTap={{ scale: 0.98 }}
            onClick={() => onSelectTheme(theme)}
            className={`relative group cursor-pointer aspect-[4/5] rounded-3xl overflow-hidden shadow-xl transition-all border-4 ${activeTheme.id === theme.id ? 'border-primary ring-4 ring-primary/20' : 'border-white/50'}`}
          >
            <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient}`}></div>
            <div className="absolute inset-0 bg-white/10 backdrop-blur-md m-2 rounded-2xl flex flex-col justify-end p-4">
              <div className={`w-8 h-8 rounded-full ${theme.iconBg} mb-2 shadow-lg flex items-center justify-center text-white`}>
                <span className="material-symbols-outlined text-sm">water_drop</span>
              </div>
              <p className={`${theme.textColor} font-bold text-sm`}>{theme.name}</p>
            </div>
            {activeTheme.id === theme.id && (
              <div className="absolute top-4 right-4 bg-primary text-white p-1 rounded-full flex items-center justify-center shadow-lg">
                <span className="material-symbols-outlined text-xs" style={{ fontVariationSettings: "'wght' 700" }}>check</span>
              </div>
            )}
          </motion.div>
        ))}
      </div>

      <div className="mt-8 flex justify-center">
        <div className="inline-flex items-center gap-2 px-5 py-3 rounded-full glass-card text-xs font-bold text-gray-500">
          <span className="material-symbols-outlined text-sm">swipe_vertical</span>
          Swipe to see more
        </div>
      </div>
    </div>
  );
};

export default ThemeSelector;

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { ChecklistItem } from '../types';
import { SUGGESTED_ITEMS } from '../constants';

interface AddItemModalProps {
  onClose: () => void;
  onAdd: (item: Omit<ChecklistItem, 'id' | 'checked'>) => void;
}

const AddItemModal: React.FC<AddItemModalProps> = ({ onClose, onAdd }) => {
  const [customLabel, setCustomLabel] = useState('');

  const handleQuickAdd = () => {
    if (customLabel.trim()) {
      onAdd({
        label: customLabel,
        subtext: 'Custom item',
        icon: 'edit_note',
        color: 'bg-emerald-100 text-emerald-600'
      });
      setCustomLabel('');
    }
  };

  return (
    <div className="absolute inset-0 z-50 flex flex-col justify-end">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/20 backdrop-blur-sm"
      />

      <motion.div
        initial={{ y: "100%" }}
        animate={{ y: 0 }}
        exit={{ y: "100%" }}
        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="relative w-full h-[85%] bg-white/80 backdrop-blur-3xl rounded-t-[3rem] shadow-2xl flex flex-col border-t border-white/20"
      >
        <div className="flex justify-center pt-4 pb-2">
          <div className="w-12 h-1.5 bg-gray-300 rounded-full"></div>
        </div>

        <div className="px-8 flex items-center justify-between pt-2 pb-6">
          <h2 className="text-2xl font-extrabold tracking-tight">Add Items</h2>
          <button 
            onClick={onClose}
            className="size-10 rounded-full bg-gray-100 flex items-center justify-center active:scale-90 transition-transform"
          >
            <span className="material-symbols-outlined text-xl">close</span>
          </button>
        </div>

        <div className="px-8 pb-6">
          <div className="relative group">
            <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none">
              <span className="material-symbols-outlined text-gray-400 group-focus-within:text-primary transition-colors">search</span>
            </div>
            <input 
              className="w-full h-14 bg-gray-100 border-none rounded-2xl pl-12 pr-4 text-base focus:ring-2 focus:ring-primary/20 placeholder:text-gray-400 transition-all font-medium" 
              placeholder="Search pre-programmed items" 
              type="text"
            />
          </div>
        </div>

        <div className="px-8 flex-1 overflow-y-auto no-scrollbar pb-32">
          <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-6">Suggested Items</h3>
          <div className="grid grid-cols-3 gap-y-8 gap-x-4">
            {SUGGESTED_ITEMS.map((item, idx) => (
              <motion.button 
                key={idx}
                whileTap={{ scale: 0.9 }}
                onClick={() => onAdd({ ...item, subtext: 'Recently added' })}
                className="flex flex-col items-center gap-3 group"
              >
                <div className={`size-16 rounded-3xl ${item.color.split(' ')[0]} flex items-center justify-center shadow-lg shadow-black/5 relative`}>
                  <span className={`material-symbols-outlined text-3xl ${item.color.split(' ')[1]}`}>{item.icon}</span>
                  <div className="absolute inset-0 rounded-3xl ring-2 ring-black/5 opacity-0 group-active:opacity-100 transition-opacity"></div>
                </div>
                <span className="text-xs font-bold text-gray-700">{item.label}</span>
              </motion.button>
            ))}
          </div>
        </div>

        <div className="absolute bottom-0 left-0 right-0 p-8 bg-white/60 backdrop-blur-xl border-t border-white/20 pb-12">
          <div className="relative flex items-center bg-white rounded-[2rem] p-2 shadow-xl ring-1 ring-black/5">
            <div className="flex items-center justify-center size-12 ml-1 rounded-2xl bg-gray-50 text-gray-400">
              <span className="material-symbols-outlined text-[24px]">edit_note</span>
            </div>
            <input 
              value={customLabel}
              onChange={(e) => setCustomLabel(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleQuickAdd()}
              className="flex-1 bg-transparent border-none focus:ring-0 text-base py-3 px-3 placeholder:text-gray-400 font-bold" 
              placeholder="Custom item name..." 
              type="text"
            />
            <button 
              onClick={handleQuickAdd}
              disabled={!customLabel.trim()}
              className="bg-black text-white size-12 rounded-2xl flex items-center justify-center shadow-md active:scale-90 transition-transform disabled:opacity-20"
            >
              <span className="material-symbols-outlined">arrow_upward</span>
            </button>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

export default AddItemModal;

