import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { INITIAL_ITEMS, THEMES } from './constants.ts';
import { ChecklistItem, Theme, View } from './types.ts';
import Dashboard from './components/Dashboard.tsx';
import ThemeSelector from './components/ThemeSelector.tsx';
import AddItemModal from './components/AddItemModal.tsx';

const App: React.FC = () => {
  const [items, setItems] = useState<ChecklistItem[]>(() => {
    try {
      const saved = localStorage.getItem('checkly-items');
      return saved ? JSON.parse(saved) : INITIAL_ITEMS;
    } catch (e) {
      return INITIAL_ITEMS;
    }
  });
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [activeTheme, setActiveTheme] = useState<Theme>(THEMES[3]);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('checkly-items', JSON.stringify(items));
  }, [items]);

  const toggleItem = useCallback((id: string) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, checked: !item.checked } : item
    ));
  }, []);

  const resetItems = useCallback(() => {
    setItems(prev => prev.map(item => ({ ...item, checked: false })));
  }, []);

  const addItem = useCallback((item: Omit<ChecklistItem, 'id' | 'checked'>) => {
    const newItem: ChecklistItem = {
      ...item,
      id: Math.random().toString(36).substring(2, 9),
      checked: false
    };
    setItems(prev => [newItem, ...prev]);
    setIsAddModalOpen(false);
  }, []);

  const deleteItem = useCallback((id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  }, []);

  return (
    <div className="min-h-screen font-sans selection:bg-primary/10">
      <div className="relative flex h-screen w-full flex-col bg-gradient-mesh overflow-hidden max-w-md mx-auto shadow-2xl border-x border-black/[0.03]">

        {/* Subtle Background Counter */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0">
          <motion.span 
            key={items.filter(i => !i.checked).length}
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 0.03, scale: 1 }}
            className="text-[240px] font-black select-none tracking-tighter text-black"
          >
            {items.filter(i => !i.checked).length}
          </motion.span>
        </div>

        <AnimatePresence mode="wait">
          {currentView === 'dashboard' && (
            <motion.div
              key="dashboard"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="h-full w-full relative z-10"
            >
              <Dashboard 
                items={items}
                onToggle={toggleItem}
                onDelete={deleteItem}
                onReset={resetItems}
                onOpenThemes={() => setCurrentView('themes')}
                onOpenAdd={() => setIsAddModalOpen(true)}
              />
            </motion.div>
          )}

          {currentView === 'themes' && (
            <motion.div
              key="themes"
              initial={{ opacity: 0, scale: 1.05 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="h-full w-full relative z-10"
            >
              <ThemeSelector 
                activeTheme={activeTheme}
                onSelectTheme={(theme) => {
                  setActiveTheme(theme);
                  setCurrentView('dashboard');
                }}
                onBack={() => setCurrentView('dashboard')}
              />
            </motion.div>
          )}
        </AnimatePresence>

        <AnimatePresence>
          {isAddModalOpen && (
            <AddItemModal 
              onClose={() => setIsAddModalOpen(false)}
              onAdd={addItem}
            />
          )}
        </AnimatePresence>

        <div className="absolute bottom-1.5 left-1/2 -translate-x-1/2 w-32 h-1 bg-black/10 rounded-full pointer-events-none z-50"></div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { motion, useMotionValue, useTransform } from 'framer-motion';
import { ChecklistItem } from '../types.ts';

interface DashboardProps {
  items: ChecklistItem[];
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
  onReset: () => void;
  onOpenThemes: () => void;
  onOpenAdd: () => void;
}

const SwipeableItem: React.FC<{
  item: ChecklistItem;
  index: number;
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
}> = ({ item, index, onToggle, onDelete }) => {
  const x = useMotionValue(0);
  const backgroundOpacity = useTransform(x, [-100, -50, 0], [1, 0.5, 0]);
  const scale = useTransform(x, [-100, -50, 0], [1, 0.9, 0.8]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 15 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95 }}
      transition={{ delay: index * 0.03, type: 'spring', damping: 25, stiffness: 300 }}
      className="relative group mb-3"
    >
      {/* Delete Action Background */}
      <motion.div 
        style={{ opacity: backgroundOpacity }}
        className="absolute inset-0 bg-danger rounded-2xl flex items-center justify-end px-6 z-0"
      >
        <motion.span style={{ scale }} className="material-symbols-outlined text-white font-bold">
          delete
        </motion.span>
      </motion.div>

      {/* Main Item Card */}
      <motion.div
        drag="x"
        dragConstraints={{ left: -100, right: 0 }}
        dragElastic={0.1}
        onDragEnd={(_, info) => {
          if (info.offset.x < -80) {
            onDelete(item.id);
          } else {
            x.set(0);
          }
        }}
        style={{ x }}
        onClick={() => onToggle(item.id)}
        className={`relative z-10 ios-card flex items-center p-4 rounded-2xl active:scale-[0.98] transition-transform shadow-sm border border-black/[0.03] cursor-pointer ${item.checked ? 'bg-white/60' : 'bg-white'}`}
      >
        <div className={`flex size-11 items-center justify-center rounded-xl ${item.color.split(' ')[0]} mr-4`}>
          <span className={`material-symbols-outlined text-xl ${item.color.split(' ')[1]}`}>
            {item.icon}
          </span>
        </div>

        <div className="flex-1 min-w-0">
          <h3 className={`text-[16px] font-semibold tracking-tight text-black transition-all ${item.checked ? 'text-black/30 line-through' : 'text-black/90'}`}>
            {item.label}
          </h3>
          <p className="text-[12px] font-medium text-black/25 truncate">
            {item.subtext}
          </p>
        </div>

        <div className={`size-6 rounded-full flex items-center justify-center transition-all duration-300 ${item.checked ? 'bg-primary border-primary' : 'border-[1.5px] border-black/10'}`}>
          {item.checked && (
            <motion.span 
              initial={{ scale: 0.5, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              className="material-symbols-outlined text-white text-[14px]" 
              style={{ fontVariationSettings: "'wght' 700" }}
            >
              check
            </motion.span>
          )}
        </div>
      </motion.div>
    </motion.div>
  );
};

const Dashboard: React.FC<DashboardProps> = ({ items, onToggle, onDelete, onReset, onOpenThemes, onOpenAdd }) => {
  const remainingCount = items.filter(i => !i.checked).length;

