import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { INITIAL_ITEMS, THEMES } from './constants.ts';
import { ChecklistItem, Theme, View } from './types.ts';
import Dashboard from './components/Dashboard.tsx';
import ThemeSelector from './components/ThemeSelector.tsx';
import AddItemModal from './components/AddItemModal.tsx';

const App: React.FC = () => {
  const [items, setItems] = useState<ChecklistItem[]>(() => {
    try {
      const saved = localStorage.getItem('checkly-items-v2');
      return saved ? JSON.parse(saved) : INITIAL_ITEMS;
    } catch (e) {
      return INITIAL_ITEMS;
    }
  });
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [activeTheme, setActiveTheme] = useState<Theme>(THEMES[0]);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('checkly-items-v2', JSON.stringify(items));
  }, [items]);

  const toggleItem = useCallback((id: string) => {
    // We still keep toggle for "dimming" but the main action is swipe to remove
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, checked: !item.checked } : item
    ));
  }, []);

  const resetItems = useCallback(() => {
    setItems([]);
  }, []);

  const addItem = useCallback((item: Omit<ChecklistItem, 'id' | 'checked'>) => {
    const newItem: ChecklistItem = {
      ...item,
      id: Math.random().toString(36).substring(2, 9),
      checked: false
    };
    setItems(prev => [newItem, ...prev]);
    setIsAddModalOpen(false);
  }, []);

  const deleteItem = useCallback((id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  }, []);

  const isDark = activeTheme.id === 'midnight' || activeTheme.id === 'space' || activeTheme.id === 'sunset';

  return (
    <div className={`min-h-screen font-sans selection:bg-primary/10 transition-colors duration-700 ${isDark ? 'bg-black' : 'bg-white'}`}>
      <div className={`relative flex h-screen w-full flex-col overflow-hidden max-w-md mx-auto shadow-2xl border-x border-black/[0.03] bg-gradient-to-br ${activeTheme.gradient}`}>

        {/* Decorative background element */}
        <div className="absolute top-[-10%] left-[-10%] size-64 bg-white/10 rounded-full blur-3xl pointer-events-none"></div>

        <AnimatePresence mode="wait">
          {currentView === 'dashboard' && (
            <motion.div
              key="dashboard"
              initial={{ opacity: 0, scale: 0.98 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 1.02 }}
              className="h-full w-full relative z-10"
            >
              <Dashboard 
                items={items}
                onToggle={toggleItem}
                onDelete={deleteItem}
                onReset={resetItems}
                onOpenThemes={() => setCurrentView('themes')}
                onOpenAdd={() => setIsAddModalOpen(true)}
                isDarkTheme={isDark}
              />
            </motion.div>
          )}

          {currentView === 'themes' && (
            <motion.div
              key="themes"
              initial={{ opacity: 0, x: 100 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -100 }}
              className="h-full w-full relative z-10"
            >
              <ThemeSelector 
                activeTheme={activeTheme}
                onSelectTheme={(theme) => {
                  setActiveTheme(theme);
                  setCurrentView('dashboard');
                }}
                onBack={() => setCurrentView('dashboard')}
              />
            </motion.div>
          )}
        </AnimatePresence>

        <AnimatePresence>
          {isAddModalOpen && (
            <AddItemModal 
              onClose={() => setIsAddModalOpen(false)}
              onAdd={addItem}
            />
          )}
        </AnimatePresence>

        <div className={`absolute bottom-1.5 left-1/2 -translate-x-1/2 w-32 h-1 rounded-full pointer-events-none z-50 ${isDark ? 'bg-white/20' : 'bg-black/10'}`}></div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { motion, useMotionValue, useTransform } from 'framer-motion';
import { ChecklistItem } from '../types.ts';

interface DashboardProps {
  items: ChecklistItem[];
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
  onReset: () => void;
  onOpenThemes: () => void;
  onOpenAdd: () => void;
  isDarkTheme: boolean;
}

const SwipeableItem: React.FC<{
  item: ChecklistItem;
  index: number;
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
  isDark: boolean;
}> = ({ item, index, onToggle, onDelete, isDark }) => {
  const x = useMotionValue(0);
  const backgroundOpacity = useTransform(x, [-120, -60, 0], [1, 0.5, 0]);
  const scaleIcon = useTransform(x, [-120, -60, 0], [1.2, 1, 0.8]);
  const rotateIcon = useTransform(x, [-120, 0], [-20, 0]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, scale: 0.9, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.8, x: -200 }}
      transition={{ 
        delay: index * 0.04, 
        type: 'spring', 
        damping: 20, 
        stiffness: 250 
      }}
      className="relative mb-3 group"
    >
      {/* Delete Action Background */}
      <motion.div 
        style={{ opacity: backgroundOpacity }}
        className="absolute inset-0 bg-[#FF3B30] rounded-[24px] flex items-center justify-end px-8 z-0 overflow-hidden"
      >
        <motion.span style={{ scale: scaleIcon, rotate: rotateIcon }} className="material-symbols-outlined text-white font-bold text-2xl">
          delete_forever
        </motion.span>
      </motion.div>

      {/* Main Item Card */}
      <motion.div
        drag="x"
        dragConstraints={{ left: -140, right: 0 }}
        dragElastic={0.08}
        onDragEnd={(_, info) => {
          if (info.offset.x < -90) {
            onDelete(item.id);
          } else {
            x.set(0);
          }
        }}
        style={{ x }}
        onClick={() => onToggle(item.id)}
        className={`relative z-10 flex items-center p-4 rounded-[24px] active:scale-[0.97] transition-all duration-300 cursor-grab active:cursor-grabbing ${isDark ? 'ios-card-dark shadow-black/20' : 'ios-card shadow-lg shadow-black/5'} ${item.checked ? 'opacity-40 saturate-50' : ''}`}
      >
        {/* Apple Contact Style Icon */}
        <div className={`flex size-12 items-center justify-center rounded-full ${item.color} mr-4 shadow-inner ring-2 ring-white/20`}>
          <span className="text-2xl leading-none select-none">{item.icon}</span>
        </div>

        <div className="flex-1 min-w-0">
          <h3 className={`text-[17px] font-bold tracking-tight transition-colors duration-300 ${isDark ? 'text-white' : 'text-slate-900'}`}>
            {item.label}
          </h3>
          <p className={`text-[13px] font-medium truncate ${isDark ? 'text-white/40' : 'text-slate-400'}`}>
            {item.subtext}
          </p>
        </div>

        {/* Subtle status indicator instead of checkbox */}
        <div className="flex items-center gap-2 opacity-20 group-hover:opacity-40 transition-opacity">
           <span className={`material-symbols-outlined text-[16px] ${isDark ? 'text-white' : 'text-black'}`}>drag_handle</span>
        </div>
      </motion.div>
    </motion.div>
  );
};

const Dashboard: React.FC<DashboardProps> = ({ items, onToggle, onDelete, onReset, onOpenThemes, onOpenAdd, isDarkTheme }) => {
  const activeCount = items.filter(i => !i.checked).length;

  return (
    <div className="relative flex h-full flex-col px-6">
