        >
          <span className={`material-symbols-outlined ${isDarkTheme ? 'text-white/80' : 'text-black/60'} text-[22px]`}>palette</span>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto no-scrollbar pb-44">
        <AnimatePresence mode="popLayout">
          {items.map((item, index) => (
            <SwipeableItem 
              key={item.id} 
              item={item} 
              index={index} 
              onToggle={onToggle} 
