          >
            <div className={`size-24 rounded-full flex items-center justify-center mb-6 ${isDarkTheme ? 'bg-white/5' : 'bg-black/5'}`}>
              <span className="text-5xl">🎒</span>
            </div>
            <h3 className={`text-xl font-bold mb-2 ${isDarkTheme ? 'text-white' : 'text-slate-900'}`}>All Caught Up!</h3>
            <p className={`text-sm font-medium leading-relaxed ${isDarkTheme ? 'text-white/30' : 'text-slate-400'}`}>
              Your pack is ready. Swipe to remove items as you grab them.
