          </motion.div>
        )}
      </main>

      {/* Floating Action Bar */}
      <div className="absolute bottom-10 left-0 right-0 px-6 flex items-center justify-between pointer-events-none z-30">
        <motion.button 
          whileTap={{ scale: 0.95 }}
          onClick={onReset}
          className={`h-14 px-8 rounded-[24px] font-extrabold text-[14px] tracking-tight pointer-events-auto transition-all ${isDarkTheme ? 'bg-white/10 text-white shadow-xl hover:bg-white/20' : 'bg-white text-slate-900 shadow-2xl hover:bg-slate-50 border border-black/[0.03]'}`}
        >
          Clear All
        </motion.button>

        <motion.button 
          whileTap={{ scale: 0.9 }}
          onClick={onOpenAdd}
          className={`size-16 flex items-center justify-center rounded-full shadow-2xl pointer-events-auto active:scale-95 transition-all ${isDarkTheme ? 'bg-white text-black shadow-white/10' : 'bg-black text-white shadow-black/20 hover:bg-slate-900'}`}
        >
          <span className="material-symbols-outlined text-4xl">add</span>
        </motion.button>
      </div>

      {/* Swipe Hint */}
      {items.length > 0 && (
        <div className="absolute bottom-28 left-0 right-0 flex justify-center pointer-events-none">
          <p className={`text-[10px] font-bold uppercase tracking-[0.2em] opacity-30 ${isDarkTheme ? 'text-white' : 'text-black'}`}>
            Swipe left to remove
          </p>
        </div>
      )}
    </div>
  );
};

