}

const SwipeableItem: React.FC<{
  item: ChecklistItem;
  index: number;
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
  isDark: boolean;
}> = ({ item, index, onToggle, onDelete, isDark }) => {
  const x = useMotionValue(0);
  const backgroundOpacity = useTransform(x, [-120, -60, 0], [1, 0.5, 0]);
  const scaleIcon = useTransform(x, [-120, -60, 0], [1.2, 1, 0.8]);
  const rotateIcon = useTransform(x, [-120, 0], [-20, 0]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, scale: 0.9, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.8, x: -200 }}
      transition={{ 
        delay: index * 0.04, 
        type: 'spring', 
        damping: 20, 
        stiffness: 250 
      }}
      className="relative mb-3 group"
    >
      {/* Delete Action Background */}
      <motion.div 
        style={{ opacity: backgroundOpacity }}
        className="absolute inset-0 bg-[#FF3B30] rounded-[24px] flex items-center justify-end px-8 z-0 overflow-hidden"
      >
        <motion.span style={{ scale: scaleIcon, rotate: rotateIcon }} className="material-symbols-outlined text-white font-bold text-2xl">
          delete_forever
        </motion.span>
      </motion.div>

      {/* Main Item Card */}
      <motion.div
        drag="x"
        dragConstraints={{ left: -140, right: 0 }}
        dragElastic={0.08}
        onDragEnd={(_, info) => {
          if (info.offset.x < -90) {
            onDelete(item.id);
          } else {
            x.set(0);
          }
        }}
        style={{ x }}
        onClick={() => onToggle(item.id)}
        className={`relative z-10 flex items-center p-4 rounded-[24px] active:scale-[0.97] transition-all duration-300 cursor-grab active:cursor-grabbing ${isDark ? 'ios-card-dark shadow-black/20' : 'ios-card shadow-lg shadow-black/5'} ${item.checked ? 'opacity-40 saturate-50' : ''}`}
