        {/* Apple Contact Style Icon */}
        <div className={`flex size-12 items-center justify-center rounded-full ${item.color} mr-4 shadow-inner ring-2 ring-white/20`}>
          <span className="text-2xl leading-none select-none">{item.icon}</span>
