import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { QRCodeSVG } from 'qrcode.react';
import { Html5Qrcode } from 'html5-qrcode';
import { ChecklistItem } from '../types.ts';

interface ShareModalProps {
  listTitle: string;
  items: ChecklistItem[];
  onClose: () => void;
  onImport: (title: string, items: ChecklistItem[]) => void;
}

const ShareModal: React.FC<ShareModalProps> = ({ listTitle, items, onClose, onImport }) => {
  const [mode, setMode] = useState<'display' | 'scan'>('display');
  const [error, setError] = useState<string | null>(null);
  const scannerRef = useRef<Html5Qrcode | null>(null);

  // Encode list data for QR
  const shareData = JSON.stringify({
    v: 1,
    title: listTitle,
    items: items.map(({ label, subtext, icon, color }) => ({ label, subtext, icon, color }))
  });

  const startScanner = async () => {
    try {
      setError(null);
      const scanner = new Html5Qrcode("qr-reader");
      scannerRef.current = scanner;

      await scanner.start(
        { facingMode: "environment" },
        {
          fps: 10,
          qrbox: { width: 250, height: 250 },
        },
        (decodedText) => {
          try {
            const data = JSON.parse(decodedText);
            if (data.v === 1 && data.title && Array.isArray(data.items)) {
              onImport(data.title, data.items);
              stopScanner();
            } else {
              setError("Invalid Pack format");
            }
          } catch (e) {
            setError("Could not read Pack QR");
          }
        },
        () => {} // silent on scan failure
      );
    } catch (err) {
      console.error(err);
      setError("Camera access denied or unavailable");
      setMode('display');
    }
  };

  const stopScanner = async () => {
    if (scannerRef.current) {
      try {
        await scannerRef.current.stop();
        scannerRef.current = null;
      } catch (e) {
        console.error("Failed to stop scanner", e);
      }
    }
  };

  useEffect(() => {
    if (mode === 'scan') {
      startScanner();
    } else {
      stopScanner();
    }
    return () => { stopScanner(); };
  }, [mode]);

  return (
    <div className="absolute inset-0 z-[110] flex flex-col items-center justify-center px-8">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/40 backdrop-blur-[20px]"
      />

      <motion.div
        initial={{ scale: 0.9, opacity: 0, y: 20 }}
        animate={{ scale: 1, opacity: 1, y: 0 }}
        exit={{ scale: 0.9, opacity: 0, y: 20 }}
        className="relative w-full max-w-[340px] aspect-square bg-white rounded-[54px] shadow-2xl flex flex-col items-center justify-center p-2 overflow-hidden"
      >
        <AnimatePresence mode="wait">
          {mode === 'display' ? (
            <motion.div 
              key="display"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setMode('scan')}
              className="w-full h-full flex flex-col items-center justify-center gap-6 cursor-pointer group"
            >
              <div className="relative p-6 bg-slate-50 rounded-[44px] transition-transform duration-500 group-hover:scale-[1.02]">
                <QRCodeSVG 
                  value={shareData} 
                  size={200} 
                  level="M" 
                  includeMargin={false}
                  className="rounded-xl"
                />
                <div className="absolute inset-0 flex items-center justify-center bg-white/80 opacity-0 group-hover:opacity-100 transition-opacity rounded-[44px]">
                  <span className="material-symbols-outlined text-4xl text-black">photo_camera</span>
                </div>
              </div>
              <div className="text-center px-6">
                <p className="text-lg font-black text-slate-900 tracking-tight leading-none mb-1">My Pack QR</p>
                <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Tap to Scan another</p>
              </div>
            </motion.div>
          ) : (
            <motion.div 
              key="scan"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="w-full h-full relative bg-black rounded-[44px] overflow-hidden group"
            >
              <div id="qr-reader" className="w-full h-full"></div>

              <div 
                onClick={() => setMode('display')}
                className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none"
              >
                <div className="w-64 h-64 border-2 border-white/50 rounded-3xl border-dashed"></div>
                {error && (
                  <div className="mt-4 px-4 py-2 bg-red-500 text-white text-xs font-bold rounded-full pointer-events-auto">
                    {error}
                  </div>
                )}
              </div>

              <button 
                onClick={() => setMode('display')}
                className="absolute bottom-6 left-1/2 -translate-x-1/2 px-6 py-2 bg-white/20 backdrop-blur-md text-white text-[10px] font-black uppercase tracking-widest rounded-full border border-white/20"
              >
                Show my QR
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>

      <motion.button
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="mt-12 size-14 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center active:scale-90 transition-all border border-white/10"
      >
        <span className="material-symbols-outlined text-white">close</span>
      </motion.button>
    </div>
  );
};

