        </AnimatePresence>
      </motion.div>

      <motion.button
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="mt-12 size-14 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center active:scale-90 transition-all border border-white/10"
      >
        <span className="material-symbols-outlined text-white">close</span>
      </motion.button>
    </div>
  );
};

export default ShareModal;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { QRCodeSVG } from 'qrcode.react';
import { Html5Qrcode } from 'html5-qrcode';
import { ChecklistItem } from '../types.ts';

interface ShareModalProps {
  listTitle: string;
  items: ChecklistItem[];
  onClose: () => void;
  onImport: (title: string, items: ChecklistItem[]) => void;
}

const ShareModal: React.FC<ShareModalProps> = ({ listTitle, items, onClose, onImport }) => {
  const [mode, setMode] = useState<'display' | 'scan'>('display');
  const [error, setError] = useState<string | null>(null);
  const [isCameraStarting, setIsCameraStarting] = useState(false);
  const scannerRef = useRef<Html5Qrcode | null>(null);

  // Encode list data for QR
  const shareData = JSON.stringify({
    v: 1,
    title: listTitle,
    items: items.map(({ label, subtext, icon, color }) => ({ label, subtext, icon, color }))
  });

  const initializeScanner = async () => {
    const elementId = "qr-reader";
    const element = document.getElementById(elementId);

    // Safety check: ensure element is in DOM
    if (!element) {
      setTimeout(initializeScanner, 150);
      return;
    }

    try {
      setError(null);
      setIsCameraStarting(true);

      const scanner = new Html5Qrcode(elementId);
      scannerRef.current = scanner;

      await scanner.start(
        { facingMode: "environment" },
        {
          fps: 15,
          qrbox: { width: 220, height: 220 },
          aspectRatio: 1.0,
        },
        (decodedText) => {
          try {
            const data = JSON.parse(decodedText);
            if (data.v === 1 && data.title && Array.isArray(data.items)) {
              // Success feedback: slight delay to let user see success
              onImport(data.title, data.items);
              stopScanner();
            } else {
              setError("Not a valid Pack QR");
            }
          } catch (e) {
            setError("Invalid QR format");
          }
        },
        () => {} // error callback - usually just no QR in frame
      );
      setIsCameraStarting(false);
    } catch (err) {
      console.error("Camera error:", err);
      setError("Camera blocked or unavailable");
      setIsCameraStarting(false);
      // Auto-fallback after error
      setTimeout(() => setMode('display'), 2000);
    }
  };

  const stopScanner = async () => {
    if (scannerRef.current) {
      try {
        if (scannerRef.current.isScanning) {
          await scannerRef.current.stop();
        }
        scannerRef.current = null;
      } catch (e) {
        console.error("Cleanup failed:", e);
      }
    }
  };

  useEffect(() => {
    if (mode === 'scan') {
      initializeScanner();
    } else {
      stopScanner();
    }
    return () => { stopScanner(); };
  }, [mode]);

  return (
    <div className="absolute inset-0 z-[110] flex flex-col items-center justify-center px-8">
      {/* Background Dimmer */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/60 backdrop-blur-[24px]"
      />

      {/* The Passport Card */}
      <motion.div
        initial={{ scale: 0.8, opacity: 0, y: 40 }}
        animate={{ scale: 1, opacity: 1, y: 0 }}
        exit={{ scale: 0.8, opacity: 0, y: 40 }}
        transition={{ type: 'spring', damping: 25, stiffness: 300 }}
        className="relative w-full max-w-[340px] aspect-[1/1.1] bg-white rounded-[48px] shadow-[0_32px_64px_-16px_rgba(0,0,0,0.5)] flex flex-col items-center p-3 overflow-hidden ring-1 ring-white/50"
      >
        {/* Iridescent Border Gradient Effect */}
        <div className="absolute inset-0 bg-gradient-to-tr from-sky-100/20 via-rose-100/20 to-violet-100/20 pointer-events-none" />

        <AnimatePresence mode="wait">
          {mode === 'display' ? (
            <motion.div 
              key="display"
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 1.05 }}
              className="w-full h-full flex flex-col items-center justify-center gap-8 relative z-10"
            >
              <div 
                onClick={() => setMode('scan')}
                className="relative p-7 bg-white rounded-[40px] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 group cursor-pointer transition-all active:scale-95"
              >
                <QRCodeSVG 
                  value={shareData} 
                  size={200} 
                  level="M" 
                  includeMargin={false}
                  className="rounded-lg"
                />

                {/* Holographic Overlay on QR */}
                <div className="absolute inset-0 bg-gradient-to-br from-white/40 via-transparent to-black/5 opacity-40 pointer-events-none rounded-[40px]" />

                {/* Scan Prompt Overlay */}
                <div className="absolute inset-0 flex items-center justify-center bg-black/80 opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-[40px] backdrop-blur-sm">
                  <div className="flex flex-col items-center gap-2">
                    <span className="material-symbols-outlined text-4xl text-white">camera_alt</span>
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">Open Scanner</span>
                  </div>
                </div>
              </div>

              <div className="text-center px-4">
                <div className="flex items-center justify-center gap-2 mb-1.5">
                   <div className="size-1.5 rounded-full bg-blue-500 animate-pulse" />
                   <p className="text-xl font-[900] text-slate-900 tracking-tight leading-none">Your Pack Card</p>
                </div>
                <p className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em] leading-tight">
                  Let a friend scan to share
                </p>
              </div>
            </motion.div>
          ) : (
            <motion.div 
              key="scan"
              initial={{ opacity: 0, scale: 1.05 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="w-full h-full relative bg-black rounded-[38px] overflow-hidden group shadow-inner"
            >
              {/* Scanner Viewport */}
              <div id="qr-reader" className="w-full h-full absolute inset-0 opacity-100 transition-opacity duration-700"></div>

              {/* Loading State Overlay */}
              {isCameraStarting && (
                <div className="absolute inset-0 bg-slate-900 flex flex-col items-center justify-center gap-4">
                   <div className="size-12 border-4 border-white/10 border-t-white rounded-full animate-spin" />
                   <p className="text-[10px] font-black text-white uppercase tracking-widest opacity-50">Waking Camera...</p>
                </div>
              )}

              {/* Scanning HUD */}
              {!isCameraStarting && (
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none z-20">
                  {/* The Focus Box */}
                  <div className="relative w-56 h-56 border-2 border-white/30 rounded-[32px] overflow-hidden">
                    {/* Corners */}
                    <div className="absolute top-0 left-0 size-8 border-t-4 border-l-4 border-white rounded-tl-xl" />
                    <div className="absolute top-0 right-0 size-8 border-t-4 border-r-4 border-white rounded-tr-xl" />
                    <div className="absolute bottom-0 left-0 size-8 border-b-4 border-l-4 border-white rounded-bl-xl" />
                    <div className="absolute bottom-0 right-0 size-8 border-b-4 border-r-4 border-white rounded-br-xl" />

                    {/* Animated Scanline */}
                    <motion.div 
                      animate={{ top: ['0%', '100%', '0%'] }}
                      transition={{ duration: 2.5, repeat: Infinity, ease: "linear" }}
                      className="absolute left-0 right-0 h-1 bg-gradient-to-r from-transparent via-white to-transparent shadow-[0_0_15px_rgba(255,255,255,0.8)]"
                    />
                  </div>

                  {error ? (
                    <motion.div 
                      initial={{ y: 10, opacity: 0 }}
                      animate={{ y: 0, opacity: 1 }}
                      className="mt-8 px-6 py-2.5 bg-rose-500/90 backdrop-blur-xl text-white text-[11px] font-black uppercase tracking-widest rounded-full border border-white/20 shadow-xl"
                    >
                      {error}
                    </motion.div>
                  ) : (
                    <p className="mt-8 text-[11px] font-black text-white uppercase tracking-[0.25em] opacity-80 drop-shadow-md">
                      Align QR in frame
                    </p>
                  )}
                </div>
              )}

              {/* Vignette Overlay */}
              <div className="absolute inset-0 bg-gradient-to-b from-black/40 via-transparent to-black/60 pointer-events-none" />

              <button 
                onClick={() => setMode('display')}
                className="absolute bottom-6 left-1/2 -translate-x-1/2 px-7 py-3 bg-white/10 hover:bg-white/20 active:scale-95 backdrop-blur-xl text-white text-[10px] font-black uppercase tracking-[0.2em] rounded-full border border-white/10 transition-all z-30 pointer-events-auto"
              >
                Back to My QR
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>

      {/* Close Button */}
      <motion.button
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: 20 }}
        onClick={onClose}
        className="mt-12 size-16 rounded-full bg-white/10 backdrop-blur-2xl flex items-center justify-center active:scale-90 transition-all border border-white/10 shadow-2xl group"
      >
        <span className="material-symbols-outlined text-white text-3xl group-hover:rotate-90 transition-transform duration-300">close</span>
      </motion.button>
    </div>
  );
};

export default ShareModal;
